import{_ as t,c as a,o as d,a5 as o}from"./chunks/framework.CgT1UzWm.js";const m=JSON.parse('{"title":"Custom Parameters Annotation","titleTemplate":"NpgsqlRest","description":"Set custom key-value configuration for PostgreSQL REST API endpoints. Add metadata and custom settings to endpoints.","frontmatter":{"outline":[2,3],"title":"Custom Parameters Annotation","titleTemplate":"NpgsqlRest","description":"Set custom key-value configuration for PostgreSQL REST API endpoints. Add metadata and custom settings to endpoints.","head":[["meta",{"name":"keywords","content":"npgsqlrest custom parameters, endpoint metadata, key value config, custom endpoint settings, api custom config"}],["meta",{"property":"og:title","content":"NpgsqlRest Custom Parameters Annotation"}],["meta",{"property":"og:description","content":"Set custom key-value configuration and metadata for endpoints."}],["meta",{"property":"og:type","content":"article"}]]},"headers":[],"relativePath":"annotations/custom-parameters.md","filePath":"annotations/custom-parameters.md"}'),r={name:"annotations/custom-parameters.md"};function s(n,e,c,i,l,h){return d(),a("div",null,e[0]||(e[0]=[o(`<h1 id="custom-parameters" tabindex="-1">Custom Parameters <a class="header-anchor" href="#custom-parameters" aria-label="Permalink to &quot;Custom Parameters&quot;">​</a></h1><p>Set custom key-value configuration for the endpoint.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@&lt;key&gt; = &lt;value&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>The <code>@</code> prefix is optional - both <code>@key = value</code> and <code>key = value</code> work identically. Custom parameters with <code>@</code> prefix are stored without the prefix (e.g., <code>@my_param = value</code> is stored as <code>my_param</code>).</p><h2 id="dynamic-parameter-values" tabindex="-1">Dynamic Parameter Values <a class="header-anchor" href="#dynamic-parameter-values" aria-label="Permalink to &quot;Dynamic Parameter Values&quot;">​</a></h2><p>Some parameters support dynamic values using the <code>{param_name}</code> format, where <code>param_name</code> references a function parameter. The value is resolved at runtime from the actual parameter value passed to the endpoint.</p><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> upload_file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(_path </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, _file </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">returns</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> void</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">language</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> sql</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $$</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  -- function body</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$$;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">comment on function upload_file(text, text) is </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">@file_system_path = {_path}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">@file_system_file = {_file}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div></details><p>When called with <code>{&quot;_path&quot;: &quot;/uploads/images&quot;, &quot;_file&quot;: &quot;photo.jpg&quot;}</code>, the file will be saved to <code>/uploads/images/photo.jpg</code>.</p><h2 id="built-in-parameters" tabindex="-1">Built-in Parameters <a class="header-anchor" href="#built-in-parameters" aria-label="Permalink to &quot;Built-in Parameters&quot;">​</a></h2><p>The following parameters are recognized by NpgsqlRest and its handlers.</p><h3 id="general-parameters" tabindex="-1">General Parameters <a class="header-anchor" href="#general-parameters" aria-label="Permalink to &quot;General Parameters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>buffer_rows</code>, <code>buffer</code></td><td>Sets the buffered amount of rows before they are written to the response.</td></tr><tr><td><code>columns</code>, <code>names</code>, <code>column_names</code></td><td>If <code>true</code> and endpoint is in raw mode, response will contain header names.</td></tr><tr><td><code>connection</code>, <code>connection_name</code></td><td>Defines an alternative connection name that must exist in the <code>ConnectionStrings</code> dictionary.</td></tr><tr><td><code>new_line</code>, <code>raw_new_line</code></td><td>Defines the separator between raw value rows when raw mode is enabled.</td></tr><tr><td><code>raw</code>, <code>raw_mode</code>, <code>raw_results</code></td><td>Sets response to raw mode where HTTP response is written exactly as received from PostgreSQL.</td></tr><tr><td><code>separator</code>, <code>raw_separator</code></td><td>Defines the separator between raw value columns when raw mode is enabled.</td></tr></tbody></table><h3 id="upload-handler-parameters" tabindex="-1">Upload Handler Parameters <a class="header-anchor" href="#upload-handler-parameters" aria-label="Permalink to &quot;Upload Handler Parameters&quot;">​</a></h3><h4 id="shared-parameters" tabindex="-1">Shared Parameters <a class="header-anchor" href="#shared-parameters" aria-label="Permalink to &quot;Shared Parameters&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>stop_after_first_success</code></td><td>When <code>true</code>, stops processing after the first successful upload handler.</td></tr><tr><td><code>included_mime_types</code></td><td>Comma-separated list of MIME type patterns to include for upload processing.</td></tr><tr><td><code>excluded_mime_types</code></td><td>Comma-separated list of MIME type patterns to exclude from upload processing.</td></tr></tbody></table><h4 id="large-object-upload-handler" tabindex="-1">Large Object Upload Handler <a class="header-anchor" href="#large-object-upload-handler" aria-label="Permalink to &quot;Large Object Upload Handler&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>buffer_size</code>, <code>large_object_buffer_size</code></td><td>Size of the buffer used for reading/writing large object data.</td></tr><tr><td><code>check_text</code>, <code>large_object_check_text</code></td><td>When <code>true</code>, checks if the uploaded content is text format.</td></tr><tr><td><code>check_image</code>, <code>large_object_check_image</code></td><td>When <code>true</code>, checks if the uploaded content is an image format.</td></tr><tr><td><code>test_buffer_size</code>, <code>large_object_test_buffer_size</code></td><td>Size of the buffer used for testing file content type.</td></tr><tr><td><code>non_printable_threshold</code>, <code>large_object_non_printable_threshold</code></td><td>Threshold for determining if content contains non-printable characters.</td></tr><tr><td><code>oid</code>, <code>large_object_oid</code></td><td>PostgreSQL large object OID to use for storage.</td></tr><tr><td><code>large_object_included_mime_types</code></td><td>MIME type patterns to include for large object upload processing.</td></tr><tr><td><code>large_object_excluded_mime_types</code></td><td>MIME type patterns to exclude from large object upload processing.</td></tr></tbody></table><h4 id="file-system-upload-handler" tabindex="-1">File System Upload Handler <a class="header-anchor" href="#file-system-upload-handler" aria-label="Permalink to &quot;File System Upload Handler&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>buffer_size</code>, <code>file_system_buffer_size</code></td><td>Size of the buffer used for reading/writing file system data.</td></tr><tr><td><code>check_text</code>, <code>file_system_check_text</code></td><td>When <code>true</code>, checks if the uploaded content is text format.</td></tr><tr><td><code>check_image</code>, <code>file_system_check_image</code></td><td>When <code>true</code>, checks if the uploaded content is an image format.</td></tr><tr><td><code>test_buffer_size</code>, <code>file_system_test_buffer_size</code></td><td>Size of the buffer used for testing file content type.</td></tr><tr><td><code>non_printable_threshold</code>, <code>file_system_non_printable_threshold</code></td><td>Threshold for determining if content contains non-printable characters.</td></tr><tr><td><code>path</code>, <code>file_system_path</code></td><td>File system path where uploaded files will be stored.</td></tr><tr><td><code>file</code>, <code>file_system_file</code></td><td>Specific file name to use for the uploaded content.</td></tr><tr><td><code>unique_name</code>, <code>file_system_unique_name</code></td><td>When <code>true</code>, generates unique file names to avoid conflicts.</td></tr><tr><td><code>create_path</code>, <code>file_system_create_path</code></td><td>When <code>true</code>, creates the directory path if it doesn&#39;t exist.</td></tr><tr><td><code>file_system_included_mime_types</code></td><td>MIME type patterns to include for file system upload processing.</td></tr><tr><td><code>file_system_excluded_mime_types</code></td><td>MIME type patterns to exclude from file system upload processing.</td></tr></tbody></table><h4 id="csv-upload-handler" tabindex="-1">CSV Upload Handler <a class="header-anchor" href="#csv-upload-handler" aria-label="Permalink to &quot;CSV Upload Handler&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>test_buffer_size</code>, <code>csv_test_buffer_size</code></td><td>Size of the buffer used for testing CSV content type.</td></tr><tr><td><code>non_printable_threshold</code>, <code>csv_non_printable_threshold</code></td><td>Threshold for determining if content contains non-printable characters.</td></tr><tr><td><code>check_format</code>, <code>csv_check_format</code></td><td>When <code>true</code>, validates the CSV format before processing.</td></tr><tr><td><code>delimiters</code>, <code>csv_delimiters</code></td><td>Characters used as field delimiters in CSV files (e.g., comma, semicolon).</td></tr><tr><td><code>has_fields_enclosed_in_quotes</code>, <code>csv_has_fields_enclosed_in_quotes</code></td><td>When <code>true</code>, expects CSV fields to be enclosed in quotes.</td></tr><tr><td><code>set_white_space_to_null</code>, <code>csv_set_white_space_to_null</code></td><td>When <code>true</code>, converts whitespace-only fields to NULL values.</td></tr><tr><td><code>row_command</code>, <code>csv_row_command</code></td><td>SQL command to execute for each CSV row during processing.</td></tr><tr><td><code>csv_included_mime_types</code></td><td>MIME type patterns to include for CSV upload processing.</td></tr><tr><td><code>csv_excluded_mime_types</code></td><td>MIME type patterns to exclude from CSV upload processing.</td></tr></tbody></table><h4 id="excel-upload-handler" tabindex="-1">Excel Upload Handler <a class="header-anchor" href="#excel-upload-handler" aria-label="Permalink to &quot;Excel Upload Handler&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>sheet_name</code>, <code>excel_sheet_name</code></td><td>Name of the specific Excel worksheet to process.</td></tr><tr><td><code>all_sheets</code>, <code>excel_all_sheets</code></td><td>When <code>true</code>, processes all worksheets in the Excel file.</td></tr><tr><td><code>time_format</code>, <code>excel_time_format</code></td><td>Format string for parsing time values from Excel cells.</td></tr><tr><td><code>date_format</code>, <code>excel_date_format</code></td><td>Format string for parsing date values from Excel cells.</td></tr><tr><td><code>datetime_format</code>, <code>excel_datetime_format</code></td><td>Format string for parsing datetime values from Excel cells.</td></tr><tr><td><code>row_is_json</code>, <code>excel_row_is_json</code></td><td>When <code>true</code>, treats each Excel row as JSON data.</td></tr><tr><td><code>row_command</code>, <code>excel_row_command</code></td><td>SQL command to execute for each Excel row during processing.</td></tr><tr><td><code>excel_included_mime_types</code></td><td>MIME type patterns to include for Excel upload processing.</td></tr><tr><td><code>excel_excluded_mime_types</code></td><td>MIME type patterns to exclude from Excel upload processing.</td></tr><tr><td><code>fallback_handler</code></td><td>Handler name to delegate to if Excel parsing fails (e.g., <code>csv</code>). Enables a single endpoint to accept both Excel and CSV files transparently.</td></tr></tbody></table><h3 id="table-format-parameters" tabindex="-1">Table Format Parameters <a class="header-anchor" href="#table-format-parameters" aria-label="Permalink to &quot;Table Format Parameters&quot;">​</a></h3><p>These parameters control how function results (from routines returning <code>SETOF</code> or <code>TABLE</code>) are rendered. See <a href="./../config/table-format.html">Table Format Options</a> for global configuration.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>table_format</code></td><td>Sets the table format renderer for the endpoint. Values: <code>html</code> (render as HTML table), <code>excel</code> (render as <code>.xlsx</code> download). Supports dynamic placeholders (e.g., <code>{_format}</code>).</td></tr><tr><td><code>excel_file_name</code></td><td>Sets the download filename for Excel table format output. Supports dynamic placeholders (e.g., <code>{_file_name}</code>).</td></tr><tr><td><code>excel_sheet</code></td><td>Sets the worksheet name for Excel table format output. Supports dynamic placeholders (e.g., <code>{_sheet_name}</code>).</td></tr></tbody></table><h3 id="sse-server-sent-events-parameters" tabindex="-1">SSE (Server-Sent Events) Parameters <a class="header-anchor" href="#sse-server-sent-events-parameters" aria-label="Permalink to &quot;SSE (Server-Sent Events) Parameters&quot;">​</a></h3><h4 id="sse-events-path" tabindex="-1">SSE Events Path <a class="header-anchor" href="#sse-events-path" aria-label="Permalink to &quot;SSE Events Path&quot;">​</a></h4><p>Additional path appended as a subpath to the main endpoint path for SSE events streaming. If the endpoint path is <code>/path</code> and this value is set to <code>/info</code>, the streaming path will be <code>/path/info</code>. Set to <code>true</code> to use the notice level name as the path.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Values</th></tr></thead><tbody><tr><td><code>sse</code>, <code>sse_path</code>, <code>sse_events_path</code></td><td><code>&lt;path&gt;</code>, <code>true</code>, <code>false</code></td></tr></tbody></table><h4 id="sse-events-level" tabindex="-1">SSE Events Level <a class="header-anchor" href="#sse-events-level" aria-label="Permalink to &quot;SSE Events Level&quot;">​</a></h4><p>Sets the PostgreSQL notice level for SSE events. Determines which PostgreSQL notice messages will be streamed to the client.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Values</th></tr></thead><tbody><tr><td><code>sse_level</code>, <code>sse_events_level</code></td><td><code>info</code>, <code>notice</code>, <code>warning</code></td></tr></tbody></table><h4 id="sse-events-scope" tabindex="-1">SSE Events Scope <a class="header-anchor" href="#sse-events-scope" aria-label="Permalink to &quot;SSE Events Scope&quot;">​</a></h4><p>Scope that determines to whom events are streamed:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Values</th></tr></thead><tbody><tr><td><code>sse_scope</code>, <code>sse_events_scope</code></td><td><code>matching</code>, <code>authorize</code>, <code>all</code>, <code>authorize role1, role2, ...</code></td></tr></tbody></table><table tabindex="0"><thead><tr><th>Scope</th><th>Description</th></tr></thead><tbody><tr><td><code>matching</code></td><td>Sessions with matching security context of the endpoint initiator.</td></tr><tr><td><code>authorize</code></td><td>Only authorized sessions receive messages. Optionally specify roles.</td></tr><tr><td><code>all</code></td><td>All sessions regardless of security context receive messages.</td></tr></tbody></table><h3 id="typescript-client-parameters" tabindex="-1">TypeScript Client Parameters <a class="header-anchor" href="#typescript-client-parameters" aria-label="Permalink to &quot;TypeScript Client Parameters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>tsclient</code></td><td>Set to <code>false</code>, <code>off</code>, <code>disabled</code>, <code>disable</code>, or <code>0</code> to disable TypeScript client code generation for the endpoint.</td></tr><tr><td><code>tsclient_events</code></td><td>Enable or disable SSE events parameter for endpoints with SSE events enabled.</td></tr><tr><td><code>tsclient_parse_url</code></td><td>Enable or disable URL parsing in generated client.</td></tr><tr><td><code>tsclient_parse_request</code></td><td>Enable or disable request parsing in generated client.</td></tr><tr><td><code>tsclient_status_code</code></td><td>Enable or disable status code in the return value.</td></tr><tr><td><code>tsclient_module</code></td><td>Sets different module name for the generated TypeScript client file.</td></tr><tr><td><code>tsclient_export_url</code></td><td>When <code>true</code>, exports a URL constant for this endpoint regardless of the global <code>ExportUrls</code> setting.</td></tr><tr><td><code>tsclient_url_only</code></td><td>When <code>true</code>, only the URL constant and request interface are exported — the fetch function and response type are skipped. Implies <code>tsclient_export_url = true</code>. Useful for endpoints consumed via browser navigation (e.g., table format downloads).</td></tr></tbody></table><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../config/npgsqlrest.html">NpgsqlRest Options configuration</a> - Configure default parameters</li><li><a href="./../config/uploads.html">Upload configuration</a> - Configure upload handlers</li><li><a href="./../guide/annotations.html">Comment Annotations Guide</a> - How annotations work</li><li><a href="./../guide/configuration.html">Configuration Guide</a> - How configuration works</li></ul>`,43)]))}const u=t(r,[["render",s]]);export{m as __pageData,u as default};
